function random(min, max) {
    return Number((Math.random() * (max - min) + min).toFixed(4));
}

function round2(value) {
    return Number(value.toFixed(2));
}

const plantId = 2;
const facilityId = 201;
const key = `energy-total:${plantId}:${facilityId}`;

const previous = context.get(key) || {
    electricity_kwh: random(8000, 12000),
    gas_m3: random(1500, 2500),
    water_ton: random(80, 130),
    solar_kwh: random(1000, 2500)
};

// 현재 부하 kW
// 1초 동안의 전력 사용량(kWh) = kW / 3600
const peakKw = random(950, 2100);
const electricityDelta = peakKw / 3600;

// 1초 단위 누적 증가량
const gasDelta = random(0.002, 0.015);
const waterDelta = random(0.001, 0.008);

// 태양광은 낮 시간대에만 증가하는 느낌
const hour = new Date().getHours();
const isDaytime = hour >= 7 && hour <= 18;
const solarDelta = isDaytime ? random(0.01, 0.12) : 0;

const next = {
    electricity_kwh: round2(previous.electricity_kwh + electricityDelta),
    gas_m3: round2(previous.gas_m3 + gasDelta),
    water_ton: round2(previous.water_ton + waterDelta),
    solar_kwh: round2(previous.solar_kwh + solarDelta)
};

context.set(key, next);

msg.topic = `scada/team5/plant/${plantId}/facility/${facilityId}/energy`;
msg.payload = JSON.stringify({
    plant_id: plantId,
    facility_id: facilityId,
    measured_at: new Date().toISOString(),

    // 누적 계량값
    electricity_kwh: next.electricity_kwh,
    gas_m3: next.gas_m3,
    water_ton: next.water_ton,
    solar_kwh: next.solar_kwh,

    // 현재 부하/피크성 값
    peak_kw: round2(peakKw)
});

return msg;

